use serde::{Deserialize, Serialize};

/// Top-level config deserialized from the .knot metadata JSON.
/// All fields are optional so existing knot files continue to parse.
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
#[serde(default)]
pub struct MolmoAct2Config {
    pub text_config: MolmoAct2TextConfig,
    pub vit_config: MolmoAct2VitConfig,
    pub adapter_config: MolmoAct2AdapterConfig,
    pub action_expert_config: MolmoAct2ActionExpertConfig,
}

/// Action expert — pi0-style flow-matching DiT denoiser.
///
/// A separate bidirectional transformer with one block per LM layer. Each block
/// runs self-attention over the action chunk, cross-attention into the
/// corresponding LM layer's K/V cache, and a SwiGLU MLP, all gated by an
/// AdaLN-Zero modulation derived from the flow-matching timestep. ALL RMSNorms
/// in the action expert are WEIGHTLESS (elementwise_affine=false).
///
/// Weight naming convention in the .knot file (mirrors HF `model.action_expert.`):
///   ae_action_embed_weight     [hidden, max_action_dim]
///   ae_action_embed_bias       [hidden]
///   ae_time1_weight            [hidden, timestep_embed_dim]   (time_embed.1)
///   ae_time1_bias              [hidden]
///   ae_time3_weight            [hidden, hidden]               (time_embed.3)
///   ae_time3_bias              [hidden]
///   ae_ctx_k_weight            [hidden, llm_kv_dim]           (no bias)
///   ae_ctx_v_weight            [hidden, llm_kv_dim]           (no bias)
///   ae_blk_{i}_sa_qkv_weight   [3*hidden, hidden]
///   ae_blk_{i}_sa_qkv_bias     [3*hidden]
///   ae_blk_{i}_sa_out_weight   [hidden, hidden]
///   ae_blk_{i}_sa_out_bias     [hidden]
///   ae_blk_{i}_ca_q_weight     [hidden, hidden]
///   ae_blk_{i}_ca_q_bias       [hidden]
///   ae_blk_{i}_ca_out_weight   [hidden, hidden]
///   ae_blk_{i}_ca_out_bias     [hidden]
///   ae_blk_{i}_mlp_gate_weight [inter, hidden]
///   ae_blk_{i}_mlp_gate_bias   [inter]
///   ae_blk_{i}_mlp_up_weight   [inter, hidden]
///   ae_blk_{i}_mlp_up_bias     [inter]
///   ae_blk_{i}_mlp_down_weight [hidden, inter]
///   ae_blk_{i}_mlp_down_bias   [hidden]
///   ae_blk_{i}_mod_weight      [9*hidden, hidden]
///   ae_blk_{i}_mod_bias        [9*hidden]
///   ae_final_mod_weight        [2*hidden, hidden]
///   ae_final_mod_bias          [2*hidden]
///   ae_final_linear_weight     [max_action_dim, hidden]
///   ae_final_linear_bias       [max_action_dim]
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct MolmoAct2ActionExpertConfig {
    pub hidden_size: usize,
    pub num_layers: usize,
    pub num_heads: usize,
    pub mlp_ratio: f32,
    pub ffn_multiple_of: usize,
    pub timestep_embed_dim: usize,
    pub qk_norm_eps: f32,
    pub rope_theta: f32,
    /// LM K/V dimension fed to the cross-attention context projections
    /// (num_key_value_heads * head_dim = 8 * 128 = 1024).
    pub llm_kv_dim: usize,
    pub max_action_horizon: usize,
    pub max_action_dim: usize,
    pub flow_matching_num_steps: usize,
}

impl Default for MolmoAct2ActionExpertConfig {
    fn default() -> Self {
        Self {
            hidden_size: 768,
            num_layers: 36,
            num_heads: 8,
            mlp_ratio: 4.0,
            ffn_multiple_of: 256,
            timestep_embed_dim: 256,
            qk_norm_eps: 1e-6,
            rope_theta: 10_000.0,
            llm_kv_dim: 1024,
            max_action_horizon: 30,
            max_action_dim: 32,
            flow_matching_num_steps: 10,
        }
    }
}

impl MolmoAct2ActionExpertConfig {
    pub fn head_dim(&self) -> usize {
        self.hidden_size / self.num_heads
    }

    /// SwiGLU inner dim, rounded up to `ffn_multiple_of` (matches HF
    /// `_round_up_multiple(hidden * mlp_ratio, multiple_of)` = 3072).
    pub fn intermediate_size(&self) -> usize {
        let raw = (self.hidden_size as f32 * self.mlp_ratio) as usize;
        raw.div_ceil(self.ffn_multiple_of) * self.ffn_multiple_of
    }
}

/// Text backbone — Qwen3-derived decoder.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct MolmoAct2TextConfig {
    pub hidden_size: usize,
    pub num_hidden_layers: usize,
    pub num_attention_heads: usize,
    pub num_key_value_heads: usize,
    pub head_dim: usize,
    pub intermediate_size: usize,
    pub vocab_size: usize,
    pub rms_norm_eps: f32,
    pub rope_theta: f32,
    /// lm_head is NOT tied to token_embd for MolmoAct2.
    pub tie_word_embeddings: bool,
}

impl Default for MolmoAct2TextConfig {
    fn default() -> Self {
        Self {
            hidden_size: 2560,
            num_hidden_layers: 36,
            num_attention_heads: 32,
            num_key_value_heads: 8,
            head_dim: 128,
            intermediate_size: 9728,
            vocab_size: 155648,
            rms_norm_eps: 1e-6,
            rope_theta: 5_000_000.0,
            tie_word_embeddings: false,
        }
    }
}

/// Custom ViT encoder.
/// 27 layers, 378×378 input, 14px patches → 729 patches.
/// float32 attention, gelu_pytorch_tanh FFN.
/// Feature extraction from layers [-3, -9] = layers 24 and 18 (0-indexed).
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct MolmoAct2VitConfig {
    pub hidden_size: usize,
    pub num_hidden_layers: usize,
    pub num_attention_heads: usize,
    pub intermediate_size: usize,
    pub image_size: usize,
    pub patch_size: usize,
    pub layer_norm_eps: f32,
    /// Which ViT layers to extract (negative = from end).
    pub extract_layers: Vec<i32>,
}

impl Default for MolmoAct2VitConfig {
    fn default() -> Self {
        Self {
            hidden_size: 1152,
            // Checkpoint stores 25 resblocks (full 27-layer ViT truncated past the
            // last extraction layer). Extract at absolute 18 and 24 (= -9, -3 of 27).
            num_hidden_layers: 25,
            num_attention_heads: 16,
            intermediate_size: 4304,
            image_size: 378,
            patch_size: 14,
            layer_norm_eps: 1e-6,
            extract_layers: vec![18, 24],
        }
    }
}

impl MolmoAct2VitConfig {
    pub fn head_dim(&self) -> usize {
        self.hidden_size / self.num_attention_heads
    }

    pub fn n_patches(&self) -> usize {
        let grid = self.image_size / self.patch_size;
        grid * grid
    }

    pub fn patch_dim(&self) -> usize {
        self.patch_size * self.patch_size * 3
    }

    /// Resolve a negative layer index to a 0-based layer index.
    pub fn resolve_layer(&self, idx: i32) -> usize {
        if idx < 0 {
            (self.num_hidden_layers as i32 + idx) as usize
        } else {
            idx as usize
        }
    }

    /// Returns sorted (ascending) extraction layer indices.
    pub fn extract_layer_indices(&self) -> Vec<usize> {
        let mut out: Vec<usize> = self
            .extract_layers
            .iter()
            .map(|&i| self.resolve_layer(i))
            .collect();
        out.sort_unstable();
        out
    }
}

/// Adapter: attention-based pooling + GLU projector.
/// Receives concatenated ViT features (n_extract_layers × vit_hidden_size).
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct MolmoAct2AdapterConfig {
    pub hidden_size: usize,
    /// Concatenated input dim (vit_hidden_size × n_extract_layers).
    pub input_dim: usize,
    pub num_attention_heads: usize,
    pub intermediate_size: usize,
    /// Output dim — must match text_config.hidden_size.
    pub text_hidden_size: usize,
    /// Number of pooled visual tokens emitted per crop (the LM-sequence length
    /// contribution of the image). With 2×2 spatial pooling of the 27×27 ViT
    /// patch grid this is 14×14 = 196 — NOT 729. (The pooling query is the
    /// per-group mean, so there is no learnable query parameter.)
    pub num_query_tokens: usize,
    pub layer_norm_eps: f32,
}

impl Default for MolmoAct2AdapterConfig {
    fn default() -> Self {
        Self {
            hidden_size: 1152,
            input_dim: 2304, // 1152 × 2 extracted layers
            num_attention_heads: 16,
            intermediate_size: 9728,
            text_hidden_size: 2560,
            num_query_tokens: 196, // 27×27 patches → 2×2 pooled → 14×14 = 196 tokens
            layer_norm_eps: 1e-6,
        }
    }
}

impl MolmoAct2AdapterConfig {
    pub fn head_dim(&self) -> usize {
        self.hidden_size / self.num_attention_heads
    }
}
